        if (sw.ElapsedMilliseconds > _warningThresholdMs)
        {
            Console.WriteLine($"WARNING: {testMethod.TestMethodName} took {sw.ElapsedMilliseconds}ms (threshold: {_warningThresholdMs}ms)");
        }

        return results;
    }
}

